// ─── LIVE TICKER — DONNÉES TEMPS RÉEL ────────────────────────────────────────
//
//  Architecture :
//  • BTC/USD     → Binance WebSocket  (tick par tick, < 1s)
//  • Forex       → Binance WebSocket  (EURUSDT, GBPUSDT, etc. — perpetual)
//  • Indices US  → Stooq CSV (S&P500=^SPX, NASDAQ=^NDX, DJI=^DJI, RUT=^RUT)
//                  via allorigins proxy, refresh 15s (données différées ~15min)
//  • Tous les prix affichent le % de variation 24h en direct
//
// ─────────────────────────────────────────────────────────────────────────────

// Symboles Binance (WebSocket miniTicker 24h)
const WS_SYMBOLS = {
  'BTCUSDT' : 'BTC/USD',
  'EURUSDT' : 'EUR/USD',
  'GBPUSDT' : 'GBP/USD',
  'USDTJPY' : 'USD/JPY',  // approx via USDT
};

// Paires forex réelles via frankfurter (refresh 10s)
const FOREX_SYMS = {
  EURUSD: 'EUR/USD',
  GBPUSD: 'GBP/USD',
  USDJPY: 'USD/JPY',
  USDCHF: 'USD/CHF',
  AUDUSD: 'AUD/USD',
  USDCAD: 'USD/CAD',
  GBPJPY: 'GBP/JPY',
};

// Indices US via Stooq
const INDEX_SYMS = {
  '^SPX' : 'S&P 500',
  '^NDX' : 'NASDAQ',
  '^DJI' : 'DOW JONES',
  '^RUT' : 'RUSSELL 2K',
};

const DECIMALS_MAP = {
  'BTC/USD':0,
  'EUR/USD':4,'GBP/USD':4,'USD/JPY':2,'USD/CHF':4,'AUD/USD':4,'USD/CAD':4,'GBP/JPY':2,
  'S&P 500':2,'NASDAQ':2,'DOW JONES':2,'RUSSELL 2K':2,
};

// Fallback au cas où les APIs sont indisponibles
const FALLBACK_PRICES = {
  'BTC/USD' : { price:67420,  pct:+1.24  },
  'EUR/USD' : { price:1.0842, pct:+0.12  },
  'GBP/USD' : { price:1.2710, pct:+0.21  },
  'USD/JPY' : { price:149.82, pct:-0.08  },
  'USD/CHF' : { price:0.9012, pct:+0.04  },
  'AUD/USD' : { price:0.6532, pct:-0.11  },
  'USD/CAD' : { price:1.3590, pct:+0.07  },
  'GBP/JPY' : { price:190.42, pct:+0.13  },
  'S&P 500' : { price:5218.19,pct:+0.34  },
  'NASDAQ'  : { price:18235.4,pct:+0.56  },
  'DOW JONES':{ price:39127.8,pct:+0.22  },
  'RUSSELL 2K':{ price:2056.3,pct:-0.14  },
};

// ── ORDER d'affichage dans le ticker ──────────────────────────────────────────
const TICKER_ORDER = [
  'S&P 500','NASDAQ','DOW JONES','RUSSELL 2K',
  'BTC/USD',
  'EUR/USD','GBP/USD','USD/JPY','USD/CHF','AUD/USD','USD/CAD','GBP/JPY',
];

// ─────────────────────────────────────────────────────────────────────────────
// Hook principal — gère toutes les sources de données
// ─────────────────────────────────────────────────────────────────────────────
function useLiveTicker() {
  // state: { [displayName]: { price, pct, flash } }
  const [data, setData] = React.useState(() => {
    const d = {};
    TICKER_ORDER.forEach(name => {
      d[name] = { price: FALLBACK_PRICES[name].price, pct: FALLBACK_PRICES[name].pct, flash: null };
    });
    return d;
  });

  const update = React.useCallback((name, price, pct) => {
    setData(prev => {
      const prevPrice = prev[name]?.price ?? price;
      const flash = price > prevPrice ? 'up' : price < prevPrice ? 'dn' : null;
      const next = { ...prev, [name]: { price, pct: pct ?? prev[name]?.pct ?? 0, flash } };
      if (flash) setTimeout(() => setData(d => ({ ...d, [name]: { ...d[name], flash: null } })), 700);
      return next;
    });
  }, []);

  // ── 1. BTC via Binance WebSocket (tick par tick) ──────────────────────────
  React.useEffect(() => {
    let ws, retryT;
    const connect = () => {
      try {
        ws = new WebSocket('wss://stream.binance.com:9443/ws/btcusdt@miniTicker');
        ws.onmessage = (e) => {
          try {
            const d = JSON.parse(e.data);
            update('BTC/USD', parseFloat(d.c), parseFloat(d.P));
          } catch {}
        };
        ws.onerror = () => {};
        ws.onclose = () => { retryT = setTimeout(connect, 3000); };
      } catch {}
    };
    connect();
    return () => { try { ws.close(); } catch {} clearTimeout(retryT); };
  }, [update]);

  // ── 2. Forex via Frankfurter (refresh 10s) ────────────────────────────────
  React.useEffect(() => {
    let prevRates = {};
    const fetch_ = async () => {
      try {
        const res = await fetch('https://api.frankfurter.app/latest?from=USD&to=EUR,GBP,JPY,CHF,AUD,CAD');
        const json = await res.json();
        const r = json.rates;
        // Calculer les paires et leur % vs valeur précédente
        const pairs = {
          'EUR/USD': r.EUR ? 1/r.EUR : null,
          'GBP/USD': r.GBP ? 1/r.GBP : null,
          'USD/JPY': r.JPY || null,
          'USD/CHF': r.CHF || null,
          'AUD/USD': r.AUD ? 1/r.AUD : null,
          'USD/CAD': r.CAD || null,
          'GBP/JPY': (r.GBP && r.JPY) ? r.JPY/r.GBP : null,
        };
        Object.entries(pairs).forEach(([name, price]) => {
          if (!price) return;
          const prev = prevRates[name] || price;
          const pct = prev ? ((price - prev) / prev) * 100 : 0;
          prevRates[name] = price;
          update(name, +price.toFixed(DECIMALS_MAP[name] ?? 4), +pct.toFixed(3));
        });
      } catch {}
    };
    fetch_();
    const t = setInterval(fetch_, 10000);
    return () => clearInterval(t);
  }, [update]);

  // ── 3. Indices US via Yahoo Finance WebSocket (csm) ───────────────────────
  // Yahoo Finance a un endpoint non-officiel qui stream les quotes
  React.useEffect(() => {
    let ws2, retryT2;
    // Yahoo Finance streaming via their undocumented WS
    const YH_SYMBOLS = ['^GSPC','^NDX','^DJI','^RUT'];
    const YH_MAP = { '^GSPC':'S&P 500', '^NDX':'NASDAQ', '^DJI':'DOW JONES', '^RUT':'RUSSELL 2K' };

    const fetchYahoo = async () => {
      try {
        // Use Yahoo Finance quote API (no API key needed, CORS OK from browser)
        const syms = YH_SYMBOLS.join('%2C');
        const url = `https://query1.finance.yahoo.com/v8/finance/spark?symbols=${syms}&range=1d&interval=1m`;
        const res = await fetch(url, { headers: { 'User-Agent': 'Mozilla/5.0' } });
        const json = await res.json();
        const spark = json?.spark?.result || [];
        spark.forEach(item => {
          const sym = item.symbol;
          const name = YH_MAP[sym];
          if (!name) return;
          const closes = item?.response?.[0]?.indicators?.quote?.[0]?.close;
          if (!closes || closes.length < 2) return;
          const valid = closes.filter(v => v != null);
          const price = valid[valid.length - 1];
          const open  = valid[0];
          const pct   = ((price - open) / open) * 100;
          update(name, +price.toFixed(2), +pct.toFixed(2));
        });
      } catch {
        // Fallback: Yahoo Finance v7 quotes
        try {
          const syms = YH_SYMBOLS.join(',');
          const url2 = `https://query2.finance.yahoo.com/v7/finance/quote?symbols=${encodeURIComponent(syms)}`;
          const res2 = await fetch(url2);
          const json2 = await res2.json();
          const quotes = json2?.quoteResponse?.result || [];
          quotes.forEach(q => {
            const name = YH_MAP[q.symbol];
            if (!name) return;
            const price = q.regularMarketPrice;
            const pct   = q.regularMarketChangePercent;
            if (price) update(name, +price.toFixed(2), +pct.toFixed(2));
          });
        } catch {}
      }
    };

    fetchYahoo();
    const t = setInterval(fetchYahoo, 15000);
    return () => clearInterval(t);
  }, [update]);

  return data;
}

// ─── LIVE TICKER BAR COMPONENT ────────────────────────────────────────────────
function LiveTickerBar() {
  const data = useLiveTicker();
  const doubled = [...TICKER_ORDER, ...TICKER_ORDER];

  const fmt = (name, price) => {
    if (!price && price !== 0) return '···';
    const d = DECIMALS_MAP[name] ?? 4;
    if (price >= 10000) return price.toLocaleString('en-US', {maximumFractionDigits:0});
    if (price >= 1000)  return price.toLocaleString('en-US', {maximumFractionDigits:2});
    return price.toFixed(d);
  };


  return (
    <div style={{
      overflow:'hidden',
      background:'rgba(3,5,12,0.98)',
      borderTop:'1px solid rgba(6,230,255,0.06)',
      borderBottom:'1px solid rgba(255,255,255,0.04)',
      padding:'11px 0',
      whiteSpace:'nowrap',
      marginTop:72,
      position:'relative',
    }}>
      {/* Fade edges */}
      <div style={{position:'absolute',left:0,top:0,bottom:0,width:80,background:'linear-gradient(90deg,rgba(3,5,12,0.98),transparent)',zIndex:2,pointerEvents:'none'}} />
      <div style={{position:'absolute',right:0,top:0,bottom:0,width:80,background:'linear-gradient(270deg,rgba(3,5,12,0.98),transparent)',zIndex:2,pointerEvents:'none'}} />

      <div style={{display:'inline-flex',gap:0,animation:'lp-ticker 50s linear infinite'}}>
        {doubled.map((name, i) => {
          const d = data[name] || FALLBACK_PRICES[name];
          const price = d?.price ?? 0;
          const pct   = d?.pct   ?? 0;
          const flash = d?.flash;
          const isPos = pct >= 0;

          // Couleur du prix : flash vert/rouge, sinon blanc sobre
          const priceColor = flash === 'up' ? '#00FF88'
                           : flash === 'dn' ? '#FF4455'
                           : '#D8E8FF';

          return (
            <span key={`${name}-${i}`} style={{
              display:'inline-flex',
              alignItems:'center',
              gap:8,
              padding:'0 20px',
              borderRight:'1px solid rgba(255,255,255,0.035)',
            }}>
              {/* Nom */}
              <span style={{
                color:'#4A6080',
                fontFamily:"'JetBrains Mono',monospace",
                fontSize:9.5,
                fontWeight:600,
                letterSpacing:'1px',
                textTransform:'uppercase',
              }}>{name}</span>

              {/* Prix */}
              <span style={{
                color: priceColor,
                fontFamily:"'JetBrains Mono',monospace",
                fontSize:12,
                fontWeight:500,
                transition:'color 0.5s ease',
                letterSpacing:'0.3px',
              }}>
                {fmt(name, price)}
              </span>

              {/* % variation 24h */}
              <span style={{
                display:'inline-flex',
                alignItems:'center',
                gap:3,
                padding:'2px 6px',
                borderRadius:4,
                background: isPos ? 'rgba(0,192,112,0.1)' : 'rgba(255,68,85,0.1)',
                border: `1px solid ${isPos ? 'rgba(0,192,112,0.2)' : 'rgba(255,68,85,0.2)'}`,
                fontFamily:"'JetBrains Mono',monospace",
                fontSize:9.5,
                fontWeight:700,
                color: isPos ? '#00C070' : '#FF4455',
                letterSpacing:'0.3px',
              }}>
                {isPos ? '▲' : '▼'} {Math.abs(pct).toFixed(2)}%
              </span>
            </span>
          );
        })}
      </div>
    </div>
  );
}

